    public async override Task<object> closePosition(object symbol, object side = null, object parameters = null)
    {
        parameters ??= new Dictionary<string, object>();
        this.checkRequiredCredentials();
        await this.loadMarkets();
        object positionId = this.safeString(parameters, "position_id");
        object amount = this.safeValue(parameters, "amount");
        if (isTrue(isEqual(positionId, null)))
        {
            object positions = await this.fetchPositions(((bool) isTrue(symbol)) ? new List<object>() {symbol} : null, parameters);
            for (object i = 0; isLessThan(i, getArrayLength(positions)); postFixIncrement(ref i))
            {
                object p = getValue(positions, i);
                if (isTrue(isTrue(!isEqual(side, null)) && isTrue(!isEqual(getValue(p, "side"), side))))
                {
                    continue;
                }
                if (isTrue(isTrue(isEqual(getValue(p, "symbol"), symbol)) || isTrue(isEqual(this.mudrexSymbol(symbol), this.mudrexSymbol(getValue(p, "symbol"))))))
                {
                    positionId = this.safeString(p, "id");
                    break;
                }
            }
        }
        if (isTrue(isEqual(positionId, null)))
        {
            throw new OrderNotFound ((string)add(this.id, " closePosition() could not resolve position_id")) ;
        }
        object request = new Dictionary<string, object>() {};
        object tradeCurrency = this.safeString2(parameters, "trade_currency", "tradeCurrency");
        if (isTrue(!isEqual(tradeCurrency, null)))
        {
            ((IDictionary<string,object>)request)["trade_currency"] = tradeCurrency;
        }
        if (isTrue(!isEqual(amount, null)))
        {
            object partialPath = add(add("futures/positions/", positionId), "/close/partial");
            object orderType = this.safeStringUpper(parameters, "order_type", "LIMIT");
            object body = this.extend(request, new Dictionary<string, object>() {
                { "order_type", orderType },
                { "quantity", ((object)amount).ToString() },
            });
            object lp = this.safeString(parameters, "limit_price");
            if (isTrue(isTrue(isEqual(orderType, "LIMIT")) && isTrue(!isEqual(lp, null))))
            {
                ((IDictionary<string,object>)body)["limit_price"] = lp;
            }
            return await this.request(partialPath, "private", "POST", this.extend(body, this.omit(parameters, new List<object>() {"trade_currency", "tradeCurrency", "order_type", "limit_price", "amount"})));
        }
        object closePath = add(add("futures/positions/", positionId), "/close");
        return await this.request(closePath, "private", "POST", this.extend(request, this.omit(parameters, new List<object>() {"trade_currency", "tradeCurrency"})));
    }

